"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import * as React from "react";
import * as ReactDOM from "react-dom";

const useIsoLayoutEffect =
  typeof window === "undefined" ? React.useEffect : React.useLayoutEffect;

type Size = { width: number; height: number };

export type SizeTransitionAxis = "both" | "width" | "height";

export type SizeTransitionProps = useRender.ComponentProps<"div"> & {
  /**
   * The value whose change triggers a transition. When it changes, the
   * outgoing content is cross-faded into the incoming `children` while the
   * element animates between the two content sizes.
   */
  transitionKey: React.Key;
  /**
   * Which dimensions to animate. Non-animated dimensions stay `auto`.
   * @default "both"
   */
  axis?: SizeTransitionAxis;
};

function measureSize(element: HTMLElement): Size {
  return { width: element.offsetWidth, height: element.offsetHeight };
}

function freezeSize(
  element: HTMLElement,
  size: Size,
  axis: SizeTransitionAxis,
) {
  if (axis !== "height") {
    element.style.setProperty("--size-width", `${size.width}px`);
  }
  if (axis !== "width") {
    element.style.setProperty("--size-height", `${size.height}px`);
  }
}

function releaseSize(element: HTMLElement) {
  element.style.removeProperty("--size-width");
  element.style.removeProperty("--size-height");
}

/**
 * Runs `callback` once every animation currently running on `element` has
 * finished. Falls back to running synchronously when the Web Animations API is
 * unavailable (e.g. jsdom) or nothing is animating.
 */
function runAfterAnimations(
  element: HTMLElement | null,
  callback: () => void,
  signal: AbortSignal,
): number {
  if (!element || typeof element.getAnimations !== "function") {
    callback();
    return -1;
  }
  // Wait a frame so freshly-triggered transitions have registered.
  return requestAnimationFrame(() => {
    if (signal.aborted) {
      return;
    }
    const animations = element.getAnimations();
    if (animations.length === 0) {
      callback();
      return;
    }
    Promise.all(animations.map((animation) => animation.finished))
      .then(() => {
        if (!signal.aborted) {
          callback();
        }
      })
      .catch(() => {
        if (!signal.aborted) {
          callback();
        }
      });
  });
}

/**
 * Animates its element between the sizes of successive `children` and
 * cross-fades the outgoing content into the incoming one whenever
 * `transitionKey` changes.
 *
 * Size is exposed as `--size-width` / `--size-height` (pixels during a
 * transition, `auto` at rest), so the consumer opts in via classes such as
 * `w-(--size-width,auto) h-(--size-height,auto) transition-[width,height]`.
 * Content layers carry Base UI's transition data attributes
 * (`data-current`, `data-previous`, `data-starting-style`, `data-ending-style`)
 * and the element carries `data-transitioning` while a transition is running.
 */
export function SizeTransition({
  axis = "both",
  transitionKey,
  children,
  render,
  ...props
}: SizeTransitionProps): React.ReactElement {
  const rootRef = React.useRef<HTMLElement | null>(null);
  const currentRef = React.useRef<HTMLDivElement | null>(null);
  const previousRef = React.useRef<HTMLDivElement | null>(null);
  // A DOM clone of the current content, refreshed after every render so the
  // outgoing subtree is available the moment `transitionKey` changes.
  const snapshotRef = React.useRef<HTMLDivElement | null>(null);
  const committedSizeRef = React.useRef<Size | null>(null);
  const previousKeyRef = React.useRef<React.Key>(transitionKey);
  const isFirstRenderRef = React.useRef(true);

  const [previousContent, setPreviousContent] =
    React.useState<HTMLDivElement | null>(null);
  const [previousSize, setPreviousSize] = React.useState<Size | null>(null);
  const [startingStyle, setStartingStyle] = React.useState(false);

  const isTransitioning = previousContent !== null;

  // Drive the size animation and cross-fade when the key changes.
  useIsoLayoutEffect(() => {
    const element = rootRef.current;
    if (!element) {
      return;
    }

    if (isFirstRenderRef.current) {
      isFirstRenderRef.current = false;
      previousKeyRef.current = transitionKey;
      committedSizeRef.current = measureSize(element);
      return;
    }

    if (previousKeyRef.current === transitionKey) {
      return;
    }
    previousKeyRef.current = transitionKey;

    const outgoingContent = snapshotRef.current;
    const previousSizeValue = committedSizeRef.current;

    if (outgoingContent) {
      setPreviousContent(outgoingContent);
      setStartingStyle(true);
    }

    // Measure the incoming content at its natural size, then keep transitions
    // suppressed on the entering layer so its `data-starting-style` snaps into
    // place (e.g. opacity 0) instead of animating away from the resting value.
    releaseSize(element);
    currentRef.current?.style.removeProperty("width");
    currentRef.current?.style.setProperty("transition", "none");
    const newSize = measureSize(element);
    committedSizeRef.current = newSize;

    // Pin the entering layer to its final width so it lays out at full size
    // from the first frame and is merely clipped while the element grows,
    // instead of reflowing (e.g. buttons shrinking) as the width animates.
    if (axis !== "height") {
      currentRef.current?.style.setProperty("width", `${newSize.width}px`);
    }

    if (previousSizeValue) {
      freezeSize(element, previousSizeValue, axis);
      setPreviousSize(previousSizeValue);
    }

    const sizeAbort = new AbortController();
    const fadeAbort = new AbortController();
    let sizeFinishFrame = -1;
    let fadeFinishFrame = -1;

    const frame = requestAnimationFrame(() => {
      // The frozen size and `data-starting-style` were committed on the
      // previous (synchronous) render but not yet computed by the browser.
      // Force a style/layout flush so the starting values are registered,
      // otherwise the browser coalesces them with the changes below and the
      // transitions never run.
      void element.offsetHeight;

      freezeSize(element, newSize, axis);
      // Re-enable the entering layer's transition now that its starting style
      // has been registered, so removing `data-starting-style` animates.
      currentRef.current?.style.removeProperty("transition");
      ReactDOM.flushSync(() => setStartingStyle(false));

      sizeFinishFrame = runAfterAnimations(
        element,
        () => {
          releaseSize(element);
          currentRef.current?.style.removeProperty("width");
        },
        sizeAbort.signal,
      );
      fadeFinishFrame = runAfterAnimations(
        currentRef.current,
        () => {
          setPreviousContent(null);
          setPreviousSize(null);
          snapshotRef.current = null;
        },
        fadeAbort.signal,
      );
    });

    return () => {
      sizeAbort.abort();
      fadeAbort.abort();
      cancelAnimationFrame(frame);
      cancelAnimationFrame(sizeFinishFrame);
      cancelAnimationFrame(fadeFinishFrame);
    };
  }, [axis, transitionKey]);

  // Populate the previous layer with the cloned outgoing subtree.
  useIsoLayoutEffect(() => {
    const container = previousRef.current;
    if (!container || !previousContent) {
      return;
    }
    container.replaceChildren(...Array.from(previousContent.childNodes));
  }, [previousContent]);

  // Snapshot the current content after every render so it can become the
  // outgoing layer on the next key change. Declared last so the transition
  // effect above reads the prior render's snapshot before it is refreshed.
  useIsoLayoutEffect(() => {
    const source = currentRef.current;
    if (!source) {
      return;
    }
    const wrapper = source.ownerDocument.createElement("div");
    for (const child of Array.from(source.childNodes)) {
      wrapper.appendChild(child.cloneNode(true));
    }
    snapshotRef.current = wrapper;
  });

  const currentLayer = (
    <div
      data-current=""
      data-starting-style={isTransitioning && startingStyle ? "" : undefined}
      key={transitionKey}
      ref={currentRef}
    >
      {children}
    </div>
  );

  const content = isTransitioning ? (
    <React.Fragment>
      <div
        data-ending-style={startingStyle ? undefined : ""}
        data-previous=""
        inert
        key="previous"
        ref={previousRef}
        style={{
          position: "absolute",
          ...(previousSize
            ? { height: previousSize.height, width: previousSize.width }
            : null),
        }}
      />
      {currentLayer}
    </React.Fragment>
  ) : (
    currentLayer
  );

  const defaultProps = {
    className: "relative",
    "data-slot": "size-transition",
  };

  return useRender({
    defaultTagName: "div",
    props: mergeProps<"div">(defaultProps, props, { children: content }),
    render,
    ref: rootRef,
    state: { transitioning: isTransitioning },
    stateAttributesMapping: {
      transitioning: (value) => (value ? { "data-transitioning": "" } : null),
    },
  });
}
